mapper.select:
SELECT DISTINCT a.user_id userId,a.user_b_id userBId,CONCAT('')cleanType, CASE a.year_check_type WHEN 1 THEN '免检代办' WHEN 2 THEN '线上年检' ELSE '年检' END AS cleanName,CONCAT('不限车型') carName,a.year_check_number cleanIndentNumber,a.price amount,a.state indentState,b.head_img imgUrl, CONCAT(1) isEvaluation,a.create_time createTime,CONCAT(5) resource,CONCAT('') rescueName,pick_address currentPosition FROM app_year_check_indent as a LEFT JOIN app_user_b_message as b ON a.user_b_id = b.user_b_id WHERE a.user_b_id = #{userBId} AND b.wrok_type =2 AND a.state <> ''
AND a.state = #{type}
order by createTime DESC LIMIT #{pagesize},20
